import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useCart } from './CartContext';

const PAYMENT_METHODS = [
  { id: 'upi', label: 'UPI', icon: '📱', desc: 'Pay via any UPI app' },
  { id: 'card', label: 'Credit / Debit Card', icon: '💳', desc: 'Visa, Mastercard, Rupay' },
  { id: 'netbanking', label: 'Net Banking', icon: '🏦', desc: 'All major banks supported' },
  { id: 'cod', label: 'Cash on Delivery', icon: '💵', desc: 'Pay when your order arrives' },
];

export default function CheckoutPage() {
  const navigate = useNavigate();
  const { cartItems, cartTotal, clearCart } = useCart();

  const shipping = cartTotal >= 999 ? 0 : 99;
  const total = cartTotal + shipping;

  const [form, setForm] = useState({
    name: '', email: '', phone: '',
    address: '', city: '', state: '', pincode: '',
  });
  const [payment, setPayment] = useState('upi');
  const [upiId, setUpiId] = useState('');
  const [errors, setErrors] = useState({});
  const [placing, setPlacing] = useState(false);

  const update = (field, value) => {
    setForm(f => ({ ...f, [field]: value }));
    setErrors(e => ({ ...e, [field]: '' }));
  };

  const validate = () => {
    const e = {};
    if (!form.name.trim()) e.name = 'Name is required';
    if (!form.email.match(/^[^\s@]+@[^\s@]+\.[^\s@]+$/)) e.email = 'Valid email required';
    if (!form.phone.match(/^[6-9]\d{9}$/)) e.phone = 'Valid 10-digit mobile number required';
    if (!form.address.trim()) e.address = 'Address is required';
    if (!form.city.trim()) e.city = 'City is required';
    if (!form.state.trim()) e.state = 'State is required';
    if (!form.pincode.match(/^\d{6}$/)) e.pincode = 'Valid 6-digit pincode required';
    if (payment === 'upi' && !upiId.includes('@')) e.upiId = 'Valid UPI ID required (e.g. name@upi)';
    return e;
  };

  const handlePlace = () => {
    const e = validate();
    if (Object.keys(e).length > 0) { setErrors(e); return; }
    setPlacing(true);
    // Simulate payment processing
    setTimeout(() => {
      clearCart();
      navigate('/order-success', {
        state: {
          orderId: 'AM' + Math.floor(100000 + Math.random() * 900000),
          total,
          name: form.name,
          address: `${form.address}, ${form.city}, ${form.state} - ${form.pincode}`,
        }
      });
    }, 1800);
  };

  if (cartItems.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] text-center px-6">
        <div className="text-6xl mb-4">🛍</div>
        <h2 className="text-xl font-bold text-ink mb-2">Your bag is empty</h2>
        <p className="text-sm text-gray-400 mb-6">Add some products before checking out</p>
        <button
          onClick={() => navigate('/')}
          className="bg-ink text-white px-6 py-2.5 rounded-lg text-sm font-semibold hover:bg-gray-800 transition-colors"
        >
          Continue Shopping
        </button>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">

      {/* Breadcrumb */}
      <div className="px-6 py-3 bg-white border-b border-gray-100 text-xs text-gray-400 flex items-center gap-2">
        <button onClick={() => navigate('/')} className="hover:text-ink transition-colors">Home</button>
        <span>›</span>
        <span className="text-ink font-medium">Checkout</span>
      </div>

      {/* Steps indicator */}
      <div className="bg-white border-b border-gray-100 px-6 py-4">
        <div className="flex items-center justify-center gap-3 max-w-lg mx-auto">
          {['Bag', 'Details', 'Payment', 'Confirm'].map((step, i) => (
            <React.Fragment key={step}>
              <div className="flex items-center gap-1.5">
                <div className={`w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold
                  ${i <= 2 ? 'bg-ink text-white' : 'bg-gray-200 text-gray-400'}`}>
                  {i + 1}
                </div>
                <span className={`text-xs font-medium hidden sm:block ${i <= 2 ? 'text-ink' : 'text-gray-400'}`}>
                  {step}
                </span>
              </div>
              {i < 3 && <div className={`flex-1 h-px ${i < 2 ? 'bg-ink' : 'bg-gray-200'}`} />}
            </React.Fragment>
          ))}
        </div>
      </div>

      <div className="max-w-5xl mx-auto px-4 py-8">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

          {/* LEFT — Form */}
          <div className="lg:col-span-2 space-y-5">

            {/* Delivery Details */}
            <div className="bg-white rounded-2xl p-6 shadow-sm">
              <h2 className="text-base font-bold text-ink mb-5 flex items-center gap-2">
                <span className="w-6 h-6 bg-ink text-white rounded-full flex items-center justify-center text-xs">1</span>
                Delivery Details
              </h2>

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                {/* Name */}
                <div>
                  <label className="text-xs font-semibold text-gray-500 block mb-1.5">Full Name *</label>
                  <input
                    value={form.name}
                    onChange={e => update('name', e.target.value)}
                    placeholder="Rahul Sharma"
                    className={`w-full border rounded-lg px-3 py-2.5 text-sm outline-none transition-colors ${errors.name ? 'border-red-400 bg-red-50' : 'border-gray-200 focus:border-ink'}`}
                  />
                  {errors.name && <p className="text-red-500 text-xs mt-1">{errors.name}</p>}
                </div>

                {/* Phone */}
                <div>
                  <label className="text-xs font-semibold text-gray-500 block mb-1.5">Mobile Number *</label>
                  <input
                    value={form.phone}
                    onChange={e => update('phone', e.target.value)}
                    placeholder="9876543210"
                    maxLength={10}
                    className={`w-full border rounded-lg px-3 py-2.5 text-sm outline-none transition-colors ${errors.phone ? 'border-red-400 bg-red-50' : 'border-gray-200 focus:border-ink'}`}
                  />
                  {errors.phone && <p className="text-red-500 text-xs mt-1">{errors.phone}</p>}
                </div>

                {/* Email */}
                <div className="sm:col-span-2">
                  <label className="text-xs font-semibold text-gray-500 block mb-1.5">Email Address *</label>
                  <input
                    value={form.email}
                    onChange={e => update('email', e.target.value)}
                    placeholder="rahul@email.com"
                    type="email"
                    className={`w-full border rounded-lg px-3 py-2.5 text-sm outline-none transition-colors ${errors.email ? 'border-red-400 bg-red-50' : 'border-gray-200 focus:border-ink'}`}
                  />
                  {errors.email && <p className="text-red-500 text-xs mt-1">{errors.email}</p>}
                </div>

                {/* Address */}
                <div className="sm:col-span-2">
                  <label className="text-xs font-semibold text-gray-500 block mb-1.5">Full Address *</label>
                  <textarea
                    value={form.address}
                    onChange={e => update('address', e.target.value)}
                    placeholder="House/Flat No., Street, Area, Landmark"
                    rows={2}
                    className={`w-full border rounded-lg px-3 py-2.5 text-sm outline-none transition-colors resize-none ${errors.address ? 'border-red-400 bg-red-50' : 'border-gray-200 focus:border-ink'}`}
                  />
                  {errors.address && <p className="text-red-500 text-xs mt-1">{errors.address}</p>}
                </div>

                {/* City */}
                <div>
                  <label className="text-xs font-semibold text-gray-500 block mb-1.5">City *</label>
                  <input
                    value={form.city}
                    onChange={e => update('city', e.target.value)}
                    placeholder="Mumbai"
                    className={`w-full border rounded-lg px-3 py-2.5 text-sm outline-none transition-colors ${errors.city ? 'border-red-400 bg-red-50' : 'border-gray-200 focus:border-ink'}`}
                  />
                  {errors.city && <p className="text-red-500 text-xs mt-1">{errors.city}</p>}
                </div>

                {/* State */}
                <div>
                  <label className="text-xs font-semibold text-gray-500 block mb-1.5">State *</label>
                  <select
                    value={form.state}
                    onChange={e => update('state', e.target.value)}
                    className={`w-full border rounded-lg px-3 py-2.5 text-sm outline-none transition-colors bg-white ${errors.state ? 'border-red-400 bg-red-50' : 'border-gray-200 focus:border-ink'}`}
                  >
                    <option value="">Select State</option>
                    {['Andhra Pradesh','Assam','Bihar','Delhi','Goa','Gujarat','Haryana','Himachal Pradesh',
                      'Jharkhand','Karnataka','Kerala','Madhya Pradesh','Maharashtra','Manipur','Meghalaya',
                      'Odisha','Punjab','Rajasthan','Tamil Nadu','Telangana','Uttar Pradesh','Uttarakhand',
                      'West Bengal'].map(s => <option key={s} value={s}>{s}</option>)}
                  </select>
                  {errors.state && <p className="text-red-500 text-xs mt-1">{errors.state}</p>}
                </div>

                {/* Pincode */}
                <div>
                  <label className="text-xs font-semibold text-gray-500 block mb-1.5">Pincode *</label>
                  <input
                    value={form.pincode}
                    onChange={e => update('pincode', e.target.value)}
                    placeholder="400001"
                    maxLength={6}
                    className={`w-full border rounded-lg px-3 py-2.5 text-sm outline-none transition-colors ${errors.pincode ? 'border-red-400 bg-red-50' : 'border-gray-200 focus:border-ink'}`}
                  />
                  {errors.pincode && <p className="text-red-500 text-xs mt-1">{errors.pincode}</p>}
                </div>
              </div>
            </div>

            {/* Payment Method */}
            <div className="bg-white rounded-2xl p-6 shadow-sm">
              <h2 className="text-base font-bold text-ink mb-5 flex items-center gap-2">
                <span className="w-6 h-6 bg-ink text-white rounded-full flex items-center justify-center text-xs">2</span>
                Payment Method
              </h2>

              <div className="space-y-3">
                {PAYMENT_METHODS.map(method => (
                  <label
                    key={method.id}
                    className={`flex items-center gap-4 p-4 rounded-xl border-2 cursor-pointer transition-all ${
                      payment === method.id ? 'border-ink bg-gray-50' : 'border-gray-200 hover:border-gray-300'
                    }`}
                  >
                    <input
                      type="radio"
                      name="payment"
                      value={method.id}
                      checked={payment === method.id}
                      onChange={() => setPayment(method.id)}
                      className="accent-ink"
                    />
                    <span className="text-2xl">{method.icon}</span>
                    <div className="flex-1">
                      <div className="text-sm font-semibold text-ink">{method.label}</div>
                      <div className="text-xs text-gray-400">{method.desc}</div>
                    </div>
                  </label>
                ))}
              </div>

              {/* UPI input */}
              {payment === 'upi' && (
                <div className="mt-4">
                  <label className="text-xs font-semibold text-gray-500 block mb-1.5">UPI ID *</label>
                  <input
                    value={upiId}
                    onChange={e => { setUpiId(e.target.value); setErrors(er => ({ ...er, upiId: '' })); }}
                    placeholder="yourname@upi"
                    className={`w-full border rounded-lg px-3 py-2.5 text-sm outline-none transition-colors ${errors.upiId ? 'border-red-400 bg-red-50' : 'border-gray-200 focus:border-ink'}`}
                  />
                  {errors.upiId && <p className="text-red-500 text-xs mt-1">{errors.upiId}</p>}
                </div>
              )}

              {/* Card fields */}
              {payment === 'card' && (
                <div className="mt-4 space-y-3">
                  <input placeholder="Card Number" maxLength={19} className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-sm outline-none focus:border-ink transition-colors" />
                  <div className="grid grid-cols-2 gap-3">
                    <input placeholder="MM / YY" maxLength={5} className="border border-gray-200 rounded-lg px-3 py-2.5 text-sm outline-none focus:border-ink transition-colors" />
                    <input placeholder="CVV" maxLength={3} type="password" className="border border-gray-200 rounded-lg px-3 py-2.5 text-sm outline-none focus:border-ink transition-colors" />
                  </div>
                  <input placeholder="Name on Card" className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-sm outline-none focus:border-ink transition-colors" />
                </div>
              )}
            </div>
          </div>

          {/* RIGHT — Order Summary */}
          <div className="space-y-4">
            <div className="bg-white rounded-2xl p-5 shadow-sm sticky top-20">
              <h2 className="text-base font-bold text-ink mb-4">Order Summary</h2>

              {/* Items */}
              <div className="space-y-3 mb-4 max-h-60 overflow-y-auto">
                {cartItems.map(item => (
                  <div key={item.id} className="flex gap-3">
                    <div className="w-14 h-16 rounded-lg overflow-hidden bg-gray-100 flex-shrink-0">
                      <img src={item.img} alt={item.name} className="w-full h-full object-cover" />
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className="text-xs font-semibold text-ink leading-snug line-clamp-2">{item.name}</p>
                      <p className="text-xs text-gray-400 mt-0.5">Qty: {item.qty}</p>
                      <p className="text-xs font-bold text-ink mt-0.5">₹{(item.price * item.qty).toLocaleString('en-IN')}</p>
                    </div>
                  </div>
                ))}
              </div>

              <div className="border-t border-gray-100 pt-4 space-y-2">
                <div className="flex justify-between text-sm text-gray-500">
                  <span>Subtotal</span>
                  <span>₹{cartTotal.toLocaleString('en-IN')}</span>
                </div>
                <div className="flex justify-between text-sm text-gray-500">
                  <span>Shipping</span>
                  <span className={shipping === 0 ? 'text-green-600 font-semibold' : ''}>
                    {shipping === 0 ? 'FREE' : `₹${shipping}`}
                  </span>
                </div>
                <div className="flex justify-between text-base font-bold text-ink pt-2 border-t border-gray-100">
                  <span>Total</span>
                  <span>₹{total.toLocaleString('en-IN')}</span>
                </div>
              </div>

              {/* Place Order */}
              <button
                onClick={handlePlace}
                disabled={placing}
                className="w-full mt-5 bg-ink text-white py-3.5 rounded-xl text-sm font-bold hover:bg-gray-800 transition-colors disabled:opacity-60 disabled:cursor-not-allowed flex items-center justify-center gap-2"
              >
                {placing ? (
                  <>
                    <svg className="animate-spin w-4 h-4" fill="none" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/>
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8H4z"/>
                    </svg>
                    Processing...
                  </>
                ) : (
                  `Place Order — ₹${total.toLocaleString('en-IN')}`
                )}
              </button>

              <p className="text-[10px] text-gray-400 text-center mt-3">
                🔒 Secure checkout · Your data is safe
              </p>
            </div>
          </div>

        </div>
      </div>
    </div>
  );
}
